package com.example.myapplication.data.local

suspend fun populateDatabase(dao: WorkoutDao) {

    if (dao.getAllExercisesOneShot().isNotEmpty()) return

    dao.deleteAllExercises()

    // Schema: Name, Group, MAJOR Muscle, MINOR Muscle, Equipment, Tier, Load, Fatigue, Movement Pattern, Recovery Hrs, Res. Profile, Note, Description
    suspend fun ex(
        name: String, group: String, major: String, minor: String?, equip: String, tierString: String, load: String, fatigue: String,
        movementPattern: String, localRecoveryHours: Int, resistanceProfile: String, note: String, desc: String
    ) {
        val tierInt = when {
            tierString.contains("Compound", ignoreCase = true) -> 1
            tierString.contains("Secondary", ignoreCase = true) -> 2
            else -> 3
        }
        val timeVal = when (tierString) {
            "Compound" -> 4.0
            "Secondary" -> 2.5
            else -> 2.0
        }
        dao.insertExercise(
            ExerciseEntity(
                name = name,
                muscleGroup = group,
                majorMuscle = major,
                minorMuscle = minor,
                equipment = equip,
                tier = tierInt,
                loadability = load,
                fatigue = fatigue,
                movementPattern = movementPattern,
                localRecoveryHours = localRecoveryHours,
                resistanceProfile = resistanceProfile,
                notes = note,
                description = desc,
                estimatedTimePerSet = timeVal
            )
        )
    }

// ==================== CHEST ====================
    ex("Barbell Bench Press", "Chest", "Pecs", "Triceps", "Barbell", "Compound", "High", "High", "Horizontal Push", 48, "Mid", "Primary horizontal push for max loading. Targets sternal pecs and triceps.", "Lie on bench, eyes under bar. Grip slightly wider than shoulders. Retract scapula. Lower bar to mid-chest (sternum) with elbows at 45 degrees. Press back up to lockout.")
    ex("Dumbbell Bench Press", "Chest", "Pecs", "Triceps", "Dumbbell", "Compound", "Med", "Med", "Horizontal Push", 48, "Lengthened", "Increases range of motion over barbell. excellent for fixing asymmetry.", "Lie on bench with dumbbells at shoulders. Press up, converging slightly at the top without touching weights together. Lower until heavy stretch is felt in pecs.")
    ex("Incline Barbell Press", "Chest", "Upper Pecs", "Front Delts", "Barbell", "Compound", "High", "High", "Incline Push", 48, "Mid", "Biases clavicular head (upper chest). Essential for full shelf development.", "Set bench to 30-45 degrees. Grip shoulder-width. Lower bar to upper chest (just below collarbone). Press vertically. Keep elbows tucked.")
    ex("Incline Dumbbell Press", "Chest", "Upper Pecs", "Front Delts", "Dumbbell", "Secondary", "Med", "Med", "Incline Push", 48, "Lengthened", "Best movement for upper chest hypertrophy due to deep stretch at bottom.", "Set bench to 30 degrees. Press dumbbells overhead. Lower deeply to stretch upper pecs, keeping forearms vertical. Press up and slightly in.")
    ex("Machine Chest Press", "Chest", "Pecs", "Triceps", "Machine", "Secondary", "High", "Low", "Horizontal Push", 48, "Mid", "Fixed path allows training to failure safely. Great for metabolic accumulation.", "Adjust seat so handles align with mid-chest. Press handles forward until arms extend. Control the negative slowly back to starting position.")
    ex("Dumbbell Fly", "Chest", "Pecs", null, "Dumbbell", "Isolation", "Low", "Low", "Horizontal Fly", 48, "Lengthened", "Biases the lengthened position (stretch). keep elbows bent to protect shoulders.", "Lie on bench. Start with weights above chest, palms facing each other. Lower weights in a wide arc with slight elbow bend until chest stretches. Squeeze back to top.")
    ex("Cable Fly", "Chest", "Pecs", null, "Cable", "Isolation", "Low", "Low", "Horizontal Fly", 24, "Shortened", "Provides constant tension especially at peak contraction (inner chest).", "Set pulleys to shoulder height. Step forward with staggered stance. Drive handles together in front of chest, squeezing hard. Control the return.")
    ex("Pec Deck", "Chest", "Pecs", null, "Machine", "Isolation", "Med", "Low", "Horizontal Fly", 24, "Shortened", "Stable isolation. Removes stabilizer fatigue to focus purely on pectorals.", "Adjust seat so elbows differ slightly below shoulders. Place forearms on pads. Squeeze elbows together in front of you. Resist the return.")
    ex("Dips (Weighted)", "Chest", "Lower Pecs", "Triceps", "Bodyweight", "Compound", "High", "High", "Vertical Push", 48, "Lengthened", "Biases lower chest and triceps. Lean forward to emphasize chest.", "Mount dip bars. Lean torso forward 30 degrees. Lower body until shoulders are below elbows. Press back up, keeping tension on chest, not shoulders.")
    ex("Push-Up", "Chest", "Pecs", "Core", "Bodyweight", "Isolation", "Low", "Low", "Horizontal Push", 24, "Mid", "Closed kinetic chain. Excellent for shoulder health and high-rep finishers.", "Plank position, hands shoulder-width. Lower chest to floor, keeping elbows tucked 45 degrees. Press up, protracting shoulder blades at the top.")
    ex("Decline Bench Press", "Chest", "Lower Pecs", "Triceps", "Barbell", "Compound", "High", "High", "Decline Push", 48, "Mid", "Biases the costal (lower) pecs. Reduces shoulder strain compared to flat bench.", "Secure legs in decline bench. Lower bar to lower sternum. Press up. Focus on the bottom half of the chest.")
    ex("Landmine Press", "Chest", "Upper Pecs", "Front Delts", "Landmine", "Secondary", "Med", "Med", "Incline Push", 48, "Mid", "Pressing path is slightly curved, excellent for upper chest and shoulder health.", "Stand or kneel. Grip end of bar with both hands or one. Lean forward slightly. Press bar up and away. Squeeze upper chest at top.")
    ex("Floor Press", "Chest", "Triceps", "Pecs", "Barbell", "Secondary", "High", "Med", "Horizontal Push", 48, "Shortened", "Limits range of motion to focus on triceps and lockout strength. Saves shoulders.", "Lie on floor. Unrack bar. Lower until elbows touch the floor (dead stop). Explode up. Do not bounce elbows off floor.")
    ex("Svend Press", "Chest", "Pecs", null, "Plate", "Isolation", "Low", "Low", "Horizontal Fly", 24, "Shortened", "Isometric tension and inner chest focus. Creates strong mind-muscle connection.", "Stand holding two plates pressed together between palms. Press plates out in front of you while squeezing them together as hard as possible. Return to chest.")
    ex("Smith Machine Bench Press", "Chest", "Pecs", "Triceps", "Machine", "Compound", "High", "Med", "Horizontal Push", 48, "Mid", "Fixed bar path allows for safe training to failure without a spotter.", "Position bench under bar. Unrack and lower to mid-chest. Press up. Removes need to stabilize front-to-back.")
    ex("Plate-Loaded Machine Press", "Chest", "Pecs", "Triceps", "Machine", "Compound", "High", "Med", "Horizontal Push", 48, "Mid", "Converging path of motion perfectly mimics natural pec function.", "Adjust seat so handles are at mid-chest level. Press forward and inward. Squeeze at peak contraction. Control the eccentric.")
    ex("High-to-Low Cable Crossover", "Chest", "Lower Pecs", null, "Cable", "Isolation", "Low", "Low", "Decline Fly", 24, "Shortened", "Biases the costal (lower) fibers of the pecs with constant tension.", "Set pulleys above head height. Grab handles, step forward. Press hands down and together in front of hips. Squeeze chest. Slowly return.")
    ex("Low-to-High Cable Fly", "Chest", "Upper Pecs", "Front Delts", "Cable", "Isolation", "Low", "Low", "Incline Fly", 24, "Shortened", "Biases the clavicular (upper) fibers of the pecs with constant tension.", "Set pulleys to lowest position. Grab handles, step forward. Drive hands up and together in front of upper chest. Slowly lower.")
    ex("Dumbbell Pullover", "Chest", "Pecs", "Lats", "Dumbbell", "Secondary", "Med", "Med", "Shoulder Extension", 48, "Lengthened", "Classic movement providing a massive loaded stretch to the pectorals and ribcage.", "Lie perpendicular across a bench with upper back supported. Hold one dumbbell with both hands straight over chest. Lower backward behind head with slight elbow bend. Pull back up to start.")
    ex("Deficit Push-Up", "Chest", "Pecs", "Triceps", "Bodyweight", "Compound", "Med", "Low", "Horizontal Push", 48, "Lengthened", "Increases range of motion over standard push-ups for a deeper pec stretch.", "Place hands on parallettes or weight plates. Lower chest past the level of your hands for a deep stretch. Press back up powerfully.")
    ex("Ring Push-Up", "Chest", "Pecs", "Core", "Bodyweight", "Compound", "Med", "Med", "Horizontal Push", 48, "Mid", "Gymnastic rings create severe instability, forcing massive pectoral recruitment.", "Set rings near floor. Grab rings and assume push-up position. Lower chest while keeping rings close to body. Press up and squeeze rings together at the top.")

// ==================== SHOULDERS ====================
    ex("Overhead Press (Standing)", "Shoulders", "Front Delts", "Triceps", "Barbell", "Compound", "High", "High", "Vertical Push", 48, "Mid", "Primary vertical push. Builds raw strength and core stability.", "Stand with bar on front delts. Grip just outside shoulders. Brace core and glutes. Move head back, press bar vertically over spine. Lock out and shrug.")
    ex("Seated Dumbbell Press", "Shoulders", "Front Delts", "Triceps", "Dumbbell", "Compound", "Med", "Med", "Vertical Push", 48, "Mid", "Hypertrophy staple. Anterior delt bias with greater ROM than barbell.", "Sit on bench with back support. Start with dumbbells at ear level. Press vertically until arms extend. Lower under control to ear level.")
    ex("Arnold Press", "Shoulders", "Front Delts", "Side Delts", "Dumbbell", "Secondary", "Med", "Med", "Vertical Push", 48, "Mid", "Hits front and side delts through rotation. increased time under tension.", "Start with palms facing you at shoulder height. Press up while rotating palms forward. Lockout with palms facing away. Reverse rotation on descent.")
    ex("Machine Shoulder Press", "Shoulders", "Front Delts", "Triceps", "Machine", "Secondary", "High", "Low", "Vertical Push", 48, "Mid", "Safe vertical push. Use for drop sets or fatigue work after free weights.", "Adjust seat so handles align with ears. Grip handles and press vertically. Lower slowly without letting weight stack touch.")
    ex("Cable Lateral Raise", "Shoulders", "Side Delts", null, "Cable", "Isolation", "Low", "Low", "Lateral Raise", 24, "Mid", "Constant tension on side delts. Critical for creating shoulder width/cap.", "Set pulley to bottom. Stand sideways. Grip handle with far hand. Raise arm out to side until parallel to floor. Control the negative.")
    ex("Face Pull", "Shoulders", "Rear Delts", "Rotator Cuff", "Cable", "Isolation", "Med", "Low", "Horizontal Pull", 24, "Shortened", "Targets rear delts and external rotators. Vital for posture and shoulder health.", "Set rope at eye level. Pull rope towards face, separating hands to pass ears. Externally rotate shoulders at end range. Squeeze rear delts.")
    ex("Rear Delt Fly (Dumbbell)", "Shoulders", "Rear Delts", null, "Dumbbell", "Isolation", "Low", "Low", "Horizontal Fly", 24, "Shortened", "Biases posterior delt. essential for the 3D look and joint balance.", "Hinge at hips until torso is parallel to floor. Let arms hang. Raise dumbbells out to sides using rear delts, not traps. Lower slowly.")
    ex("Reverse Pec Deck", "Shoulders", "Rear Delts", null, "Machine", "Isolation", "Med", "Low", "Horizontal Fly", 24, "Shortened", "Stable rear delt isolation. Easier to execute than dumbbell variations.", "Face the machine. Grip handles with arms straight. Pull arms back in a wide arc until inline with body. Squeeze rear delts. Return slowly.")
    ex("Upright Row", "Shoulders", "Side Delts", "Traps", "Barbell", "Secondary", "Med", "Med", "Vertical Pull", 48, "Mid", "Compound movement for side delts and traps. Use wide grip to avoid impingement.", "Hold bar with wide grip (outside thighs). Pull elbows up and out to shoulder height. Keep bar close to body. Lower under control.")
    ex("Egyptian Lateral Raise", "Shoulders", "Side Delts", null, "Cable", "Isolation", "Low", "Low", "Lateral Raise", 24, "Lengthened", "Leaning away increases range of motion and puts constant tension on side delt.", "Hold rack with one hand, lean away. Hold cable in other hand. Raise arm to side. The lean changes the resistance curve.")
    ex("Lu Raise", "Shoulders", "Side Delts", "Traps", "Plate", "Isolation", "Low", "Low", "Lateral Raise", 24, "Mid", "Full range of motion lateral raise used by Chinese weightlifters. Hits traps and delts.", "Hold plates. Raise laterally all the way overhead until plates touch. Control the descent. Improves shoulder mobility.")
    ex("Dumbbell Lateral Raise", "Shoulders", "Side Delts", null, "Dumbbell", "Isolation", "Low", "Low", "Lateral Raise", 24, "Mid", "The fundamental movement for side delt hypertrophy and creating shoulder width.", "Stand holding dumbbells at sides. Raise arms out to the sides with a slight elbow bend until parallel to the floor. Lower under control.")
    ex("Machine Lateral Raise", "Shoulders", "Side Delts", null, "Machine", "Isolation", "Low", "Low", "Lateral Raise", 24, "Mid", "Removes stability requirements to allow training the side delts to absolute failure safely.", "Adjust seat so pivot point aligns with shoulders. Press arms out against pads to shoulder height. Squeeze at top and control the descent.")
    ex("Cable Y-Raise", "Shoulders", "Side Delts", "Lower Traps", "Cable", "Isolation", "Low", "Med", "Vertical Pull", 24, "Shortened", "Puts the side delts in a unique stretched position while engaging the lower traps.", "Set dual cables to lowest position. Cross cables, grip handles, and raise arms diagonally overhead into a Y shape. Lower under control.")
    ex("Push Press", "Shoulders", "Front Delts", "Triceps", "Barbell", "Compound", "High", "Med", "Vertical Push", 48, "Mid", "Uses leg drive to overload the shoulders with heavier weight than strict pressing allows.", "Start with bar on front delts. Perform a quick quarter-squat dip, then explosively drive up to press the weight overhead. Lock out.")
    ex("Dumbbell Front Raise", "Shoulders", "Front Delts", null, "Dumbbell", "Isolation", "Low", "Low", "Front Raise", 24, "Mid", "Pure isolation for the anterior head. Useful for finishing off the front delts without tricep fatigue.", "Stand with dumbbells in front of thighs. Raise weight straight forward to shoulder height with arms relatively straight. Lower slowly.")
    ex("Barbell Shrug", "Shoulders", "Traps", "Forearms", "Barbell", "Isolation", "Med", "Low", "Shrug", 48, "Mid", "The absolute standard for building upper trap thickness. Allows for maximum loading.", "Hold barbell with an overhand grip outside thighs. Shrug shoulders straight up towards ears without bending elbows. Control the drop.")
    ex("Dumbbell Shrug", "Shoulders", "Traps", "Forearms", "Dumbbell", "Isolation", "Low", "Low", "Shrug", 48, "Mid", "Provides a more neutral arm position than the barbell shrug for comfortable trap isolation.", "Stand with heavy dumbbells hanging at sides. Elevate shoulders straight up towards ears. Squeeze hard at the top and lower.")
    ex("Z-Press", "Shoulders", "Front Delts", "Core", "Barbell", "Compound", "High", "High", "Vertical Push", 48, "Mid", "Forces strict form and immense core stabilization by removing leg drive entirely.", "Sit flat on the floor with legs straight out. Unrack barbell and press overhead. Keep torso perfectly upright. Lower back to clavicle.")

// ==================== BACK ====================
    ex("Seated Row (V-Grip)", "Back", "Lats", "Lower Traps", "Cable", "Secondary", "Med", "Low", "Horizontal Pull", 48, "Mid", "Close neutral grip keeps elbows tucked to bias lats and mid-back thickness.", "Attach V-handle. Sit upright. Pull handle to low stomach. Keep elbows glued to your sides to minimize upper back involvement. Squeeze lats.")
    ex("Seated Row (Wide Grip)", "Back", "Rhomboids", "Rear Delts", "Cable", "Secondary", "Med", "Low", "Horizontal Pull", 48, "Mid", "Wide pronated grip forces elbows out. Biases upper back details and rear delts.", "Attach wide lat bar. Grip wider than shoulders. Pull bar to upper chest/sternum. Flare elbows out to 45 degrees. Squeeze shoulder blades together.")
    ex("Seated Row (Single Arm)", "Back", "Lats", "Obliques", "Cable", "Isolation", "Low", "Low", "Horizontal Pull", 48, "Lengthened", "Unilateral variation allows for greater range of motion and thoracic rotation.", "Attach D-handle. Sit with feet wide. Pull handle to hip while rotating torso slightly towards the pulling arm. Stretch deep forward on release.")
    ex("Seated Row (Rope)", "Back", "Rear Delts", "Rhomboids", "Cable", "Isolation", "Low", "Low", "Horizontal Pull", 24, "Shortened", "Focuses on rear delts and external rotation. Improves posture.", "Attach rope. Pull towards upper chest. At the peak of contraction, pull hands apart (spread the rope) to fully shorten rear delts.")
    ex("Pull-Up", "Back", "Lats", "Biceps", "Bodyweight", "Compound", "High", "High", "Vertical Pull", 48, "Mid", "Primary vertical pull. Builds lat width and upper back density.", "Hang from bar with overhand grip slightly wider than shoulders. Drive elbows down to ribs to pull chin over bar. Lower to full dead hang.")
    ex("Lat Pulldown", "Back", "Lats", "Biceps", "Cable", "Secondary", "Med", "Low", "Vertical Pull", 48, "Mid", "Scalable vertical pull. Focus on driving elbows down for lat width.", "Sit with knees secured. Grip wide. Lean back slightly. Pull bar to upper chest, driving elbows down and back. Squeeze lats. Release slowly.")
    ex("Barbell Row", "Back", "Lats", "Rhomboids", "Barbell", "Compound", "High", "High", "Horizontal Pull", 48, "Mid", "Primary horizontal pull. Builds back thickness and erector strength.", "Hinge forward 45-90 degrees. Grip bar. Pull bar to lower chest/upper stomach. Squeeze shoulder blades together. Lower to full arm extension.")
    ex("Dumbbell Row", "Back", "Lats", "Biceps", "Dumbbell", "Secondary", "Med", "Med", "Horizontal Pull", 48, "Lengthened", "Unilateral row. Allows greater ROM and helps fix strength imbalances.", "Place one knee and hand on bench. Flat back. Pull dumbbell to hip pocket, driving elbow back. Lower until a deep stretch is felt in lat.")
    ex("Seated Cable Row", "Back", "Rhomboids", "Lats", "Cable", "Secondary", "Med", "Low", "Horizontal Pull", 48, "Mid", "Mid-back bias. Good for targets rhomboids and traps without lower back strain.", "Sit with feet braced. Grip attachment. Keep torso upright. Pull handle to stomach, retracting scapula fully. Extend arms forward to stretch lats.")
    ex("T-Bar Row", "Back", "Rhomboids", "Erectors", "Machine", "Compound", "High", "Med", "Horizontal Pull", 48, "Mid", "Heavy supported row. Adds thickness with less shear force than barbell rows.", "Straddle the bar. Hinge at hips. Grip handles. Pull weight to chest while keeping spine neutral. Lower carefully.")
    ex("Chest Supported Row", "Back", "Lats", "Rhomboids", "Machine", "Secondary", "Med", "Low", "Horizontal Pull", 48, "Mid", "Strict isolation. Removes momentum to target lats or upper back precisely.", "Adjust chest pad height. Grip handles. Pull elbows back hard while keeping chest glued to the pad. Squeeze back. Return to start.")
    ex("Straight Arm Pulldown", "Back", "Lats", "Triceps", "Cable", "Isolation", "Low", "Low", "Shoulder Extension", 24, "Mid", "Lat isolation (extension). Great pre-exhaust or finisher movement.", "Stand facing rope attachment. Arms straight, hinge slightly. Push bar/rope down to hips using lats. Keep elbows locked. return to eye level.")
    ex("Shrugs", "Back", "Traps", null, "Dumbbell", "Isolation", "High", "Low", "Shrug", 48, "Mid", "Upper trap isolation. Builds the yoke.", "Hold heavy dumbbells at sides. Elevate shoulders towards ears as high as possible. Pause at top. Lower fully.")
    ex("Lat Pulldown (Reverse Grip)", "Back", "Lats", "Biceps", "Cable", "Secondary", "Med", "Med", "Vertical Pull", 48, "Mid", "Supinated grip biases lower lats and biceps. Allows for greater range of motion.", "Grip bar shoulder-width with palms facing you. Lean back slightly. Pull bar to lower chest. Drive elbows down and in. Squeeze hard at bottom.")
    ex("Lat Pulldown (V-Grip)", "Back", "Lats", "Rhomboids", "Cable", "Secondary", "Med", "Med", "Vertical Pull", 48, "Mid", "Neutral close grip biases the mid-back and lat thickness. Reduces shoulder strain.", "Attach V-handle. Arch back slightly. Pull handle to top of sternum. Focus on retracting shoulder blades fully at the bottom of the movement.")
    ex("Lat Pulldown (Single Arm)", "Back", "Lats", null, "Cable", "Isolation", "Low", "Low", "Vertical Pull", 24, "Lengthened", "Unilateral focus. Allows for lateral flexion of the spine to fully shorten the lat.", "Attach D-handle. Kneel or sit. Rotate palm from pronated at top to neutral at bottom. Drive elbow down into your hip pocket. Crunch side slightly.")
    ex("Meadows Row", "Back", "Lats", "Rear Delts", "Landmine", "Secondary", "High", "High", "Horizontal Pull", 48, "Lengthened", "Unilateral row created by John Meadows. Maximizes lat stretch and grip strength.", "Stand perpendicular to landmine bar. Grip the fat end of the bar. Hinge hips. Drive elbow up and back. Allow shoulder to protract (stretch) at the bottom.")
    ex("Pendlay Row", "Back", "Lats", "Erectors", "Barbell", "Compound", "High", "High", "Horizontal Pull", 48, "Mid", "Explosive power development. Strict form required, generating force from dead stop.", "Torso parallel to floor. Bar rests on floor between reps. Explode bar to upper stomach. Return bar to floor completely. Do not use hip momentum.")
    ex("Rack Pull", "Back", "Erectors", "Traps", "Barbell", "Compound", "High", "High", "Hip Hinge", 72, "Mid", "Overloads the lockout and upper back thickness. Reduces leg fatigue compared to deadlifts.", "Set pins just below knees. Setup like a deadlift. Drag bar up thighs. Lock out hips and upper back forcefully. Lower under control.")
    ex("Deadlift", "Back", "Erectors", "Hamstrings", "Barbell", "Compound", "High", "High", "Hip Hinge", 72, "Mid", "The king of posterior chain builders. Heavily taxes the lower back, traps, and mid-back.", "Stand with mid-foot under bar. Hinge to grip bar. Drop hips, lift chest, brace core. Drive through the floor to stand. Lock out hips and knees. Return to floor.")
    ex("Chin-Up", "Back", "Lats", "Biceps", "Bodyweight", "Compound", "High", "High", "Vertical Pull", 48, "Mid", "Supinated vertical pull. Highly effective for lower lat and bicep recruitment.", "Hang with underhand grip shoulder-width apart. Pull body up until chin clears the bar. Lower under control to a full stretch.")
    ex("Seal Row", "Back", "Mid Back", "Lats", "Barbell", "Secondary", "High", "Low", "Horizontal Pull", 48, "Mid", "Strict horizontal pull. Bench supports torso, entirely removing lower back and momentum.", "Lie face down on an elevated flat bench. Grab barbell beneath you. Pull bar up until it touches the underside of the bench. Lower fully.")
    ex("Yates Row", "Back", "Lats", "Biceps", "Barbell", "Compound", "High", "High", "Horizontal Pull", 48, "Mid", "Underhand barbell row with a more upright torso. Biases the lower lats and allows heavy loading.", "Hinge forward slightly (around 30 degrees). Use a supinated (underhand) grip. Pull bar to the lower stomach/hips. Keep elbows tucked.")
    ex("Back Extension", "Back", "Erectors", "Glutes", "Bodyweight", "Secondary", "Med", "Low", "Hip Hinge", 48, "Mid", "Isolates the lumbar erectors. Crucial for lower back health and posterior chain endurance.", "Lock ankles into hyperextension bench. Hinge at hips to lower torso. Squeeze erectors and glutes to raise torso back until parallel to legs.")
    ex("Machine Pullover", "Back", "Lats", "Serratus", "Machine", "Isolation", "Med", "Low", "Shoulder Extension", 24, "Mid", "Provides constant tension through the lat's entire range of motion without bicep fatigue.", "Sit in machine, strap in. Place elbows on pads and grip handles. Drive elbows down and back in a sweeping arc. Stretch fully on the eccentric.")

// ==================== LEGS ====================
    ex("Leg Press (High Stance)", "Legs", "Glutes", "Hamstrings", "Machine", "Secondary", "High", "Med", "Squat", 48, "Mid", "Placing feet high on platform increases hip flexion, biasing glutes.", "Place feet high on the platform, shoulder width. Lower weight deep. Drive through heels. You should feel less tension on knees, more on hips.")
    ex("Leg Press (Low Stance)", "Legs", "Quads", null, "Machine", "Secondary", "High", "Med", "Squat", 48, "Mid", "Placing feet low increases knee flexion, biasing quadriceps.", "Place feet low on platform. Keep heels down (do not let them lift). Drive up. Note: Requires good ankle mobility.")
    ex("Leg Press (Wide Stance)", "Legs", "Adductors", "Glutes", "Machine", "Secondary", "High", "Med", "Squat", 48, "Mid", "Sumo stance recruits adductors (inner thigh) and glutes.", "Place feet wide and turn toes out 30 degrees. Knees must track over toes during descent. Drive through outer heel.")
    ex("Deadlift", "Legs", "Hamstrings", "Erectors", "Barbell", "Compound", "High", "High", "Hip Hinge", 72, "Mid", "Full posterior chain driver. High systemic fatigue; limits recovery resources.", "Mid-foot under bar. Hinge hips back. Grip bar. Pull slack out until you hear a 'click'. Drive feet into floor to stand up. Lock hips, do not hyperextend.")
    ex("Squat (High Bar)", "Legs", "Quads", "Glutes", "Barbell", "Compound", "High", "High", "Squat", 72, "Mid", "The king of leg movements. Biases quads/glutes with high systemic load.", "Place bar on traps. Feet shoulder-width. Brace core. Break at hips and knees simultaneously. Descend until hip crease is below knee. Drive up.")
    ex("Front Squat", "Legs", "Quads", "Core", "Barbell", "Compound", "High", "High", "Squat", 72, "Mid", "Upright torso biases quadriceps heavily. requires thoracic mobility.", "Rack bar on front delts with crossed arms or clean grip. Keep elbows high. Squat deep while maintaining upright torso. Drive up through heels.")
    ex("Leg Press", "Legs", "Quads", "Glutes", "Machine", "Secondary", "High", "Med", "Squat", 48, "Mid", "High loading capacity with no spinal compression. Ideal for volume.", "Sit in machine. Place feet hip-width on platform. Lower weight until knees are near chest (ensure lower back stays flat). Press back up.")
    ex("Hack Squat", "Legs", "Quads", "Glutes", "Machine", "Compound", "High", "Med", "Squat", 48, "Lengthened", "Fixed path allows deep knee flexion. Excellent for quad hypertrophy.", "Shoulders under pads. Feet lower on platform for quad bias. Unlock safeties. Squat deep. Drive up through legs without locking knees.")
    ex("Bulgarian Split Squat", "Legs", "Quads", "Glutes", "Dumbbell", "Secondary", "Med", "High", "Lunge", 48, "Lengthened", "Unilateral powerhouse. Fixes imbalances and challenges stability heavily.", "Place rear foot on bench. Step front foot forward. Lower hips straight down until back knee almost touches floor. Drive up through front heel.")
    ex("Romanian Deadlift", "Legs", "Hamstrings", "Glutes", "Barbell", "Compound", "High", "Med", "Hip Hinge", 72, "Lengthened", "Hip hinge focusing on hamstring stretch and glutes. Less fatigue than deadlift.", "Start standing with bar. Unlock knees slightly. Hinge hips BACK as far as possible while sliding bar down thighs. Feel hamstring stretch. Drive hips forward.")
    ex("Leg Extension", "Legs", "Quads", null, "Machine", "Isolation", "Med", "Low", "Knee Extension", 24, "Shortened", "Rectus femoris isolation. The only way to train quads in shortened position.", "Adjust pad to ankle. Sit back. Extend knees until legs are straight. Squeeze quads hard at the top. Lower under control.")
    ex("Leg Curl (Seated)", "Legs", "Hamstrings", null, "Machine", "Isolation", "Med", "Low", "Knee Flexion", 24, "Mid", "Hamstring isolation (knee flexion). Essential for knee joint health.", "Adjust lap pad tight. Legs straight on pad. Curl heels down and under seat. Squeeze hamstrings. Return slowly to start.")
    ex("Calf Raise (Standing)", "Legs", "Calves", null, "Machine", "Isolation", "Med", "Low", "Plantar Flexion", 24, "Lengthened", "Targets gastrocnemius. Keep knee straight for maximum activation.", "Shoulders under pads. Balls of feet on step. Lower heels as far as possible for stretch. Press up onto big toes. Squeeze top.")
    ex("Hip Thrust", "Legs", "Glutes", "Hamstrings", "Barbell", "Compound", "High", "Med", "Hip Extension", 48, "Shortened", "Direct glute max driver. Focuses on peak contraction (shortened position).", "Back against bench. Bar over hips. Drive hips up until body is flat table-top. Squeeze glutes hard. Chin tucked. Lower hips to floor.")
    ex("Seated Calf Raise", "Legs", "Calves", null, "Machine", "Isolation", "Low", "Low", "Plantar Flexion", 24, "Lengthened", "Biases the Soleus muscle (underneath calf) because the knee is bent.", "Sit with pads over thighs. Lower heels deep for stretch. Press up on toes. Essential for calf width.")
    ex("Nordic Hamstring Curl", "Legs", "Hamstrings", "Glutes", "Bodyweight", "Secondary", "High", "High", "Knee Flexion", 48, "Lengthened", "Eccentric overload. The gold standard for hamstring injury prevention.", "Kneel with ankles secured. Lower torso slowly to floor, resisting gravity with hamstrings. Catch yourself with hands, push back up to start.")
    ex("Sissy Squat", "Legs", "Quads", null, "Bodyweight", "Isolation", "Med", "Med", "Knee Extension", 48, "Lengthened", "Isolates rectus femoris in fully lengthened position. Extreme quad stretch.", "Lock feet. Lean torso back while driving knees forward and down. Body forms straight line from knees to head. Descend until knees near floor. Drive up.")
    ex("Walking Lunge", "Legs", "Quads", "Glutes", "Dumbbell", "Secondary", "Med", "High", "Lunge", 48, "Mid", "Dynamic unilateral movement. Increases metabolic demand and functional stability.", "Step forward, dropping back knee to floor. Drive through front heel to step into next lunge. Keep torso upright for quads, lean for glutes.")
    ex("Zercher Squat", "Legs", "Quads", "Core", "Barbell", "Compound", "High", "High", "Squat", 72, "Mid", "Anterior load challenges core and upper back immensely. Builds mental toughness.", "Hold bar in the crooks of elbows. Clasp hands. Squat deep. Keep elbows high and away from thighs. Fight to keep chest up.")
    ex("Squat (Low Bar)", "Legs", "Glutes", "Hamstrings", "Barbell", "Compound", "High", "High", "Squat", 72, "Mid", "Powerlifting standard. Shifts load to posterior chain, allowing more weight.", "Place bar low on rear delts/mid-traps. Hinge hips back further than high bar. Descend to parallel. Drive hips up and forward.")
    ex("Good Morning", "Legs", "Hamstrings", "Erectors", "Barbell", "Compound", "High", "Med", "Hip Hinge", 72, "Lengthened", "Excellent hamstring stretch and lower back strengthener.", "Place bar on upper back. Soften knees. Hinge hips back until torso is near parallel to floor. Drive hips forward to stand.")
    ex("Leg Curl (Lying)", "Legs", "Hamstrings", null, "Machine", "Isolation", "Med", "Low", "Knee Flexion", 24, "Shortened", "Isolates hamstrings with extended hips, complementing the seated curl.", "Lie face down. Align knees with pivot. Hook ankles under pad. Curl heels to glutes. Lower under control.")
    ex("Goblet Squat", "Legs", "Quads", "Core", "Dumbbell", "Secondary", "Med", "Low", "Squat", 48, "Mid", "Anterior load promotes upright torso and deep knee flexion. Great for mobility.", "Hold dumbbell or kettlebell vertically at chest. Squat down between legs, keeping chest up. Drive through floor to stand.")
    ex("Hip Abduction", "Legs", "Glute Medius", "Outer Thigh", "Machine", "Isolation", "Low", "Low", "Hip Abduction", 24, "Shortened", "Targets the upper/side glutes, crucial for pelvic stability and aesthetics.", "Sit in machine with pads outside knees. Press knees outward against resistance. Squeeze peak contraction. Return slowly.")
    ex("Hip Adduction", "Legs", "Adductors", "Inner Thigh", "Machine", "Isolation", "Low", "Low", "Hip Adduction", 24, "Shortened", "Targets the inner thigh muscles, improving squat stability and leg mass.", "Sit in machine with pads inside knees. Squeeze knees together against resistance. Control the eccentric phase.")
    ex("Cable Glute Kickback", "Legs", "Glute Maximus", null, "Cable", "Isolation", "Low", "Low", "Hip Extension", 24, "Shortened", "Pure glute isolation. Great for finishing the glutes without quad/hamstring fatigue.", "Attach ankle strap to low cable. Face machine, hold support. Kick working leg straight back, squeezing glute. Do not arch lower back.")

// ==================== ARMS ====================
    ex("Barbell Curl", "Arms", "Biceps", null, "Barbell", "Secondary", "High", "Low", "Elbow Flexion", 48, "Mid", "Mass builder for biceps. Allows heavy loading but can stress wrists.", "Stand tall. Grip bar shoulder-width, palms up. Curl bar to chest keeping elbows at sides. Lower fully to thighs.")
    ex("Dumbbell Curl", "Arms", "Biceps", null, "Dumbbell", "Isolation", "Med", "Low", "Elbow Flexion", 24, "Mid", "Supination activates peak contraction. The standard hypertrophy curl.", "Stand with dumbbells. Curl up while rotating pinky finger towards ceiling. Squeeze bicep. Lower and rotate back to neutral.")
    ex("Hammer Curl", "Arms", "Brachialis", "Forearms", "Dumbbell", "Isolation", "High", "Low", "Elbow Flexion", 24, "Mid", "Targets brachialis and brachioradialis. Adds width to the arm.", "Hold dumbbells with neutral grip (palms facing body). Curl weight up without rotating wrist. Lower slowly.")
    ex("Rope Hammer Curl", "Arms", "Brachialis", "Forearms", "Cable", "Isolation", "Med", "Low", "Elbow Flexion", 24, "Mid", "Cable provides constant tension unlike dumbbells. Builds arm thickness.", "Attach rope to low pulley. Hold neutral grip. Curl up, keeping elbows at sides. Spread rope slightly at top for contraction.")
    ex("Behind-the-Back Cable Curl", "Arms", "Biceps", null, "Cable", "Isolation", "Low", "Low", "Elbow Flexion", 24, "Lengthened", "Shoulder extension stretches the long head of the bicep maximally.", "Face away from machine. Handle in one hand, arm behind you. Curl forward while keeping elbow pinned back. Huge stretch focus.")
    ex("Preacher Curl", "Arms", "Biceps", null, "Machine", "Isolation", "Med", "Low", "Elbow Flexion", 24, "Shortened", "Targets the short head. Focus on the stretch, avoid full lockout.", "Armpits over pad. Arms extended. Curl weight up without lifting elbows off pad. Lower slowly to full stretch.")
    ex("Close Grip Bench", "Arms", "Triceps", "Chest", "Barbell", "Compound", "High", "Med", "Horizontal Push", 48, "Mid", "Compound pusher. Allows heaviest loading for triceps overall mass.", "Setup like bench press but grip shoulder-width. Lower bar to lower chest, keeping elbows tucked close to torso. Press up.")
    ex("Skullcrusher", "Arms", "Triceps", null, "EZ_Bar", "Secondary", "Med", "Low", "Elbow Extension", 48, "Lengthened", "Targets long head of triceps. Elbow position determines stretch focus.", "Lie on bench. Hold EZ bar above chest. Bend elbows to lower bar to forehead/behind head. Extend arms back to start.")
    ex("Cable Pushdown (Rope)", "Arms", "Triceps", null, "Cable", "Isolation", "Med", "Low", "Elbow Extension", 24, "Shortened", "Targets lateral head. Good for pump and joint health.", "Attach rope. Keep elbows pinned to sides. Extend elbows to separate rope at the bottom. Squeeze triceps. Return to 90 degrees.")
    ex("Overhead Extension", "Arms", "Triceps", null, "Dumbbell", "Isolation", "Med", "Low", "Elbow Extension", 24, "Lengthened", "Maximizes long head stretch. Crucial for massive triceps look.", "Sit or stand. Hold one dumbbell with both hands overhead. Lower weight behind head for deep stretch. Press back up to ceiling.")
    ex("Incline Dumbbell Curl", "Arms", "Biceps", null, "Dumbbell", "Isolation", "Med", "Low", "Elbow Flexion", 24, "Lengthened", "Biases the long head of the biceps by placing shoulder in extension (behind body).", "Set bench to 45 degrees. Let arms hang straight down. Curl without moving elbows forward. Maximum stretch focus.")
    ex("Spider Curl", "Arms", "Biceps", null, "Barbell", "Isolation", "Low", "Low", "Elbow Flexion", 24, "Shortened", "Biases the short head of the biceps in the shortened position. Eliminates cheating.", "Lie chest-down on incline bench. Arms hanging. Curl bar up towards forehead. Squeeze peak contraction hard.")
    ex("JM Press", "Arms", "Triceps", "Chest", "Barbell", "Secondary", "High", "Med", "Horizontal Push", 48, "Mid", "Hybrid between close grip press and skullcrusher. Heavy loading for tricep thickness.", "Lower bar towards neck, allowing elbows to drift forward slightly. Press back up using triceps. Keep elbows tucked.")
    ex("Cable Pushdown (Straight Bar)", "Arms", "Triceps", null, "Cable", "Secondary", "High", "Low", "Elbow Extension", 24, "Mid", "Allows for heavier loading than rope. Biases the lateral (outer) head.", "Attach straight bar or V-bar. Overhand grip. Lean forward slightly. Push bar down until elbows lock out. Keep wrists neutral.")
    ex("Cable Pushdown (Reverse Grip)", "Arms", "Triceps", "Forearms", "Cable", "Isolation", "Low", "Low", "Elbow Extension", 24, "Shortened", "Underhand grip biases the medial (inner) head. Lighter weight, stricter form.", "Attach straight bar. Supinated (palms up) grip. Keep elbows pinned to sides. Extend downwards. Great for elbow health.")
    ex("Single Arm Gold Pushdown", "Arms", "Triceps", null, "Cable", "Isolation", "Low", "Low", "Elbow Extension", 24, "Shortened", "Isolates one arm to fix strength imbalances. Usage of D-handle or no attachment.", "Grip cable directly or use D-handle. Palm facing body. Extend arm fully. Focus on squeezing the tricep without shoulder movement.")
    ex("Bayesian Curl", "Arms", "Biceps", null, "Cable", "Isolation", "Low", "Low", "Elbow Flexion", 24, "Lengthened", "Constant tension throughout full ROM. Matches strength curve of biceps perfectly.", "Face away from cable stack. Hand behind body. Curl handle forward. Allow arm to be pulled back behind body on eccentric.")
    ex("EZ-Bar Curl", "Arms", "Biceps", "Forearms", "EZ_Bar", "Secondary", "Med", "Low", "Elbow Flexion", 24, "Mid", "Hypertrophy staple that significantly reduces wrist and elbow strain compared to a straight barbell.", "Stand tall. Grip the angled bends of the bar. Curl weight up while keeping elbows pinned to your sides. Lower under control.")
    ex("Concentration Curl", "Arms", "Biceps", null, "Dumbbell", "Isolation", "Low", "Low", "Elbow Flexion", 24, "Shortened", "Strict isolation that removes momentum to focus heavily on the short head and peak contraction.", "Sit on a bench. Rest elbow against the inside of your thigh. Curl the dumbbell towards your chest. Squeeze hard at the top.")
    ex("Reverse Curl", "Arms", "Brachioradialis", "Biceps", "Barbell", "Secondary", "Med", "Low", "Elbow Flexion", 24, "Mid", "Pronated grip shifts focus heavily to the forearms and brachialis to build thick, strong arms.", "Stand tall. Grip barbell with an overhand (pronated) grip. Curl the weight up while keeping wrists straight. Lower slowly.")
    ex("Seated Wrist Curl", "Arms", "Forearms", null, "Barbell", "Isolation", "Low", "Low", "Wrist Flexion", 24, "Mid", "Direct isolation for the forearm flexors (the meaty underside of the forearm).", "Sit on bench. Rest forearms on thighs with wrists hanging over the edge, palms up. Allow bar to roll down fingers, then curl wrist up.")
    ex("Seated Reverse Wrist Curl", "Arms", "Forearms", null, "Barbell", "Isolation", "Low", "Low", "Wrist Extension", 24, "Mid", "Direct isolation for the forearm extensors (top of the forearm). Vital for preventing elbow pain.", "Sit on bench. Rest forearms on thighs with wrists hanging over the edge, palms down. Extend wrists upward as high as possible. Lower fully.")
    ex("Cable Kickback", "Arms", "Triceps", null, "Cable", "Isolation", "Low", "Low", "Elbow Extension", 24, "Shortened", "Isolates the triceps in the fully shortened position. Cables provide constant tension, unlike dumbbells.", "Attach D-handle to low cable. Hinge forward. Pin upper arm parallel to floor. Extend elbow straight back until arm is fully straight. Squeeze.")
    ex("Tricep Dip", "Arms", "Triceps", "Lower Pecs", "Bodyweight", "Compound", "High", "Med", "Vertical Push", 48, "Lengthened", "Heavy compound movement for triceps mass. Upright posture shifts tension away from the chest.", "Mount dip bars. Keep torso vertical and elbows tucked close to your sides. Lower until elbows hit 90 degrees. Press up to strict lockout.")

// ==================== OLYMPIC LIFTING ====================
    ex("Barbell Snatch", "Full Body", "Full Body", "Shoulders", "Barbell", "Compound", "High", "High", "Olympic Weightlifting", 72, "Mid", "Highest technical demand. Always schedule first in the session.", "Wide grip. Hips low. Pull bar from floor, accelerate past knees, explode hips (contact), pull under bar, catch in overhead squat.")
    ex("Clean and Jerk", "Full Body", "Full Body", "Legs", "Barbell", "Compound", "High", "High", "Olympic Weightlifting", 72, "Mid", "Primary test of strength-speed. Builds explosive power.", "Clean: Pull bar, extend hips, catch in front squat. Stand. Jerk: Dip, drive bar overhead while splitting legs. Recover feet.")
    ex("Power Clean", "Full Body", "Full Body", "Traps", "Barbell", "Compound", "High", "Med", "Olympic Weightlifting", 48, "Mid", "Athletic power development. Focus on triple extension.", "Setup like deadlift. Explode hips forward. Shrug and pull under bar. Catch on shoulders in quarter squat position. Stand up.")
    ex("Hang Clean", "Full Body", "Full Body", "Traps", "Barbell", "Secondary", "High", "Med", "Olympic Weightlifting", 48, "Mid", "Focuses on the second pull and turnover speed.", "Start standing with bar. Lower to just above knees. Explode hips forward, shrug, and catch on shoulders.")
    ex("Overhead Squat", "Legs", "Quads", "Shoulders", "Barbell", "Secondary", "Med", "Med", "Squat", 48, "Mid", "Ultimate test of core stability and mobility. light weight/high focus.", "Press bar overhead with wide snatch grip. Lock elbows active. Squat deep while keeping bar over mid-foot. Drive up.")
    ex("Push Press", "Shoulders", "Front Delts", "Triceps", "Barbell", "Secondary", "High", "Med", "Vertical Push", 48, "Mid", "Uses leg drive to overload the overhead lockout portion.", "Rack bar on shoulders. Dip knees slightly (torso vertical). Drive up with legs and finish with arm press overhead. Lockout.")

// ==================== CROSSFIT / FUNCTIONAL ====================
    ex("Thruster", "Full Body", "Quads", "Shoulders", "Barbell", "Compound", "Med", "High", "Squat", 48, "Mid", "High metabolic demand. Combines front squat and press.", "Front rack position. Perform full front squat. As you stand, use momentum to press bar overhead in one fluid motion.")
    ex("Handstand Push-Up", "Shoulders", "Front Delts", "Triceps", "Bodyweight", "Compound", "Med", "Med", "Vertical Push", 48, "Mid", "High skill gymnastics. Builds relative strength and balance.", "Kick up to wall handstand. Lower head to floor. Press back up to lockout. Keep core tight and bodyline straight.")
    ex("Box Jump", "Legs", "Quads", "Calves", "Bodyweight", "Secondary", "Low", "Med", "Plyometric", 48, "Mid", "Plyometric power. Step down to save achilles tendons.", "Stand facing box. Swing arms and dip hips. Explode up, landing softly on box with both feet. Stand tall. Step down.")
    ex("Toes-to-Bar", "Core", "Abs", "Lats", "Bodyweight", "Secondary", "Low", "Med", "Core Flexion", 24, "Shortened", "Gymnastic core work. requires grip strength and rhythm.", "Hang from bar. Kip slightly. Snap legs up to touch toes to the bar between hands. Return to hollow body position.")
    ex("Double Under", "Cardio", "Calves", "Cardio", "Bodyweight", "Isolation", "Low", "High", "Locomotion", 24, "Mid", "High intensity conditioning. Spikes heart rate quickly.", "Jump rope where rope passes twice under feet per jump. Jump higher and spin wrists faster than single unders.")

// ==================== POWERLIFTING SPECIFIC ====================
    ex("Pause Squat", "Legs", "Quads", "Glutes", "Barbell", "Secondary", "High", "High", "Squat", 72, "Lengthened", "Builds power out of the hole and reinforces bracing.", "Perform squat but stop at bottom for 2 second count. Explode up. Do not bounce out of the hole.")
    ex("Pin Squat", "Legs", "Quads", "Glutes", "Barbell", "Secondary", "High", "High", "Squat", 72, "Mid", "Overloads specific sticking points by limiting ROM.", "Set safety pins in rack to desired depth. Squat down until bar rests on pins. Pause. Drive up from dead stop.")
    ex("Spoto Press", "Chest", "Pecs", "Triceps", "Barbell", "Secondary", "High", "Med", "Horizontal Push", 48, "Mid", "Pause one inch off chest. Builds reversal strength and stability.", "Bench press but stop bar 1-2 inches above chest. Pause for 1 second. Press up. Maintain tension, do not relax.")
    ex("Deficit Deadlift", "Back", "Hamstrings", "Erectors", "Barbell", "Secondary", "High", "High", "Hip Hinge", 72, "Lengthened", "Increases ROM to strengthen floor pull. Very taxing.", "Stand on 1-2 inch plate/platform. Perform conventional deadlift. Focus on leg drive to break floor.")
    ex("Board Press", "Arms", "Triceps", "Pecs", "Barbell", "Secondary", "High", "Med", "Horizontal Push", 48, "Shortened", "Overloads the lockout (triceps). Allows supramaximal weight.", "Place 1-3 board block on chest. Lower bar to touch board. Press up. Focuses on top range of motion.")

// ==================== KETTLEBELL ====================
    ex("Kettlebell Swing (Russian)", "Legs", "Glutes", "Hamstrings", "Kettlebell", "Compound", "High", "Med", "Hip Hinge", 48, "Mid", "Explosive hip hinge. Primary driver is glute max, not shoulders. Keep spine neutral.", "Hinge hips back, hiking KB between legs. Snap hips forward explosively to float KB to chest height. Do not pull with arms.")
    ex("Goblet Squat", "Legs", "Quads", "Core", "Kettlebell", "Secondary", "Med", "Med", "Squat", 48, "Mid", "Front-loaded squat. Counterbalance helps achieve depth. Excellent for teaching squat mechanics.", "Hold KB by horns at chest. Squat deep, elbows inside knees. Keep chest up. Drive up through heels.")
    ex("Turkish Get-Up", "Full Body", "Shoulders", "Core", "Kettlebell", "Compound", "High", "High", "Functional", 48, "Mid", "Complex stabilizer. Massive time under tension for rotator cuff. Moves through multiple planes.", "Lie on back, KB pressed up. Roll to elbow, then hand. Bridge hips, sweep leg under. Lunge up to stand. Reverse perfectly.")
    ex("Kettlebell Snatch", "Full Body", "Hamstrings", "Shoulders", "Kettlebell", "Compound", "High", "High", "Olympic Weightlifting", 48, "Mid", "High-intensity ballistic movement. Requires forceful hip extension and shoulder stability.", "One-arm swing setup. Hips drive KB up. Punch hand through handle at top to lock out overhead without banging wrist.")
    ex("Single Arm Clean & Press", "Shoulders", "Front Delts", "Core", "Kettlebell", "Compound", "High", "Med", "Functional", 48, "Mid", "Unilateral power. Smooth transition from hip drive to overhead lockout. Fixes asymmetries.", "Clean KB to rack position (thumb to chest). Press overhead. Lower to rack, then floor.")
    ex("Kettlebell Halo", "Shoulders", "Shoulders", "Core", "Kettlebell", "Isolation", "Low", "Low", "Mobility", 24, "Mid", "Dynamic mobility for shoulder girdle. Anti-extension core work. Keep ribs down.", "Hold KB bottoms-up by horns. Circle it tightly around head. Keep core braced and ribs down. Do not arch back.")
    ex("Farmers Carry", "Full Body", "Forearms", "Traps", "Kettlebell", "Secondary", "High", "Med", "Carry", 48, "Mid", "Moving plank. Challenges weight strength and postural alignment under heavy load.", "Deadlift two heavy KBs. Walk with quick, short steps. Shoulders back, core tight. Do not let weights swing.")
    ex("Single Leg RDL", "Legs", "Hamstrings", "Glutes", "Kettlebell", "Secondary", "Med", "Med", "Hip Hinge", 48, "Lengthened", "Unilateral hip hinge. Challenges balance and fixes left/right hamstring strength imbalances.", "Hold KB in opposite hand to standing leg. Hinge hip back while lifting other leg straight back. Torso/leg form straight line. Return.")
    ex("Gorilla Row", "Back", "Lats", "Core", "Kettlebell", "Secondary", "Med", "Med", "Horizontal Pull", 48, "Mid", "Alternating row from dead stop. Reduces spinal shear force compared to barbell rows.", "Wide stance, two KBs on floor. Hinge down. Row one KB while pushing the other into floor. Alternate sides.")
    ex("Windmill", "Core", "Obliques", "Shoulders", "Kettlebell", "Secondary", "Med", "Low", "Mobility", 24, "Lengthened", "Lateral flexion and stabilization. Increases hip mobility and shoulder resilience.", "Press KB overhead. Look at KB. Hinge at hips, sliding free hand down inside of leg towards floor. Keep back leg straight. Stand up.")

// ==================== CORE & ABS ====================
    ex("Plank", "Core", "Abs", "Obliques", "Bodyweight", "Isolation", "Low", "Low", "Core Anti-Extension", 24, "Mid", "Foundational isometric core strength. Essential for spinal stability.", "Maintain a straight line from head to heels. Brace abs and glutes. Breathe shallowly through the nose.")
    ex("Hanging Leg Raise", "Core", "Abs", "Hip Flexors", "Bodyweight", "Secondary", "Low", "Med", "Core Flexion", 24, "Shortened", "Advanced core movement. Biases the lower abdominal fibers and grip.", "Hang from bar. Keep legs straight. Raise feet to bar level. Control the eccentric. Do not swing.")
    ex("Ab Wheel Rollout", "Core", "Abs", "Lats", "Ab Wheel", "Secondary", "Med", "High", "Core Anti-Extension", 48, "Lengthened", "Extreme eccentric loading for the core. Must keep lower back from arching.", "Kneel with wheel. Roll forward until torso is near floor. Brace hard. Pull back using abs, not hips.")
    ex("Russian Twist", "Core", "Obliques", "Abs", "Bodyweight", "Isolation", "Low", "Low", "Core Rotation", 24, "Mid", "Rotational core stability. Can be weighted with a plate or dumbbell.", "Sit with knees bent, feet off floor. Rotate torso side to side, touching floor. Move from the ribs, not just the arms.")
    ex("Cable Woodchopper", "Core", "Obliques", "Shoulders", "Cable", "Isolation", "Low", "Low", "Core Rotation", 24, "Mid", "Functional rotational power. Matches the mechanics of swinging or throwing.", "Set cable to high position. Pull diagonally down across body to opposite hip. Pivot back foot. Return slowly.")
    ex("Deadbug", "Core", "Abs", "Erectors", "Bodyweight", "Isolation", "Low", "Low", "Core Anti-Extension", 24, "Mid", "Teaches pelvic control and anti-extension. Excellent for rehab and warmup.", "Lie on back. Raise arms and legs (90 deg). Lower opposite arm and leg together while keeping lower back glued to floor. Alternate.")

// ==================== JOINT RESILIENCE & MOBILITY ====================
    ex("Copenhagen Plank", "Core", "Adductors", "Obliques", "Bodyweight", "Isolation", "Low", "Med", "Hip Adduction", 48, "Mid", "Endurance staple. Builds hip adductor strength to prevent groin and knee issues.", "Place top foot on bench. Lift bottom leg and hold hips high in a side plank. Feel tension in inner thigh of top leg.")
    ex("Terminal Knee Extension (TKE)", "Legs", "Quads", null, "Band", "Isolation", "Low", "Low", "Knee Extension", 24, "Shortened", "Isolates the VMO (medial quad). Critical for patellar tracking and runner's knee.", "Loop band behind knee. Step back for tension. Straighten leg against band resistance, squeezing the inner quad hard. Pause.")
    ex("90/90 Hip Rotations", "Legs", "Hips", null, "Bodyweight", "Isolation", "Low", "Low", "Mobility", 24, "Mid", "Endurance mobility staple. Improves internal and external hip rotation range.", "Sit with legs in 90/90 position. Rotate torso and switch knees to the other side without using hands for support. Keep spine tall.")
    ex("Single-Leg Squat (Pistol)", "Legs", "Quads", "Glutes", "Bodyweight", "Secondary", "Med", "High", "Squat", 72, "Lengthened", "Ultimate test of unilateral leg strength and balance. High stability demand.", "Stand on one leg. Extend other leg forward. Squat deep on standing leg until hamstrings touch calf. Drive up. Use support if needed.")
    ex("Glute Bridge", "Legs", "Glutes", "Hamstrings", "Bodyweight", "Isolation", "Low", "Low", "Hip Extension", 24, "Shortened", "Isolates glutes with zero spinal loading. High activation for endurance runners.", "Lie on back, feet flat. Drive hips up until knees, hips, and shoulders form a line. Squeeze glutes hard. Lower under control.")
    ex("Adductor Machine", "Legs", "Adductors", null, "Machine", "Isolation", "Med", "Low", "Hip Adduction", 24, "Shortened", "Physique/Endurance stability. Builds inner thigh mass and pelvic resilience.", "Sit in machine with legs wide. Squeeze pads together. Pause. Resist the weight as legs open. Keep torso upright.")
    ex("Abductor Machine", "Legs", "Glute Medius", null, "Machine", "Isolation", "Med", "Low", "Hip Abduction", 24, "Shortened", "Isolates the side glutes. Essential for knee stability and 'shelf' look.", "Sit in machine. Push pads outward using outer hips. Pause. Return slowly. Focus on the upper side of the glutes.")

// ==================== EXTRA VARIATIONS ====================
    ex("Hammer Strength Row", "Back", "Lats", "Rhomboids", "Machine", "Secondary", "High", "Low", "Horizontal Pull", 48, "Mid", "Plate-loaded unilateral row. Allows for extreme contraction and safe failure.", "Sit in machine. Grip handle. Pull back hard, driving elbow to hip. Squeeze the lat. Use one arm at a time for better focus.")
    ex("Lateral Raise Machine", "Shoulders", "Side Delts", null, "Machine", "Isolation", "Med", "Low", "Lateral Raise", 24, "Mid", "Stable side delt isolation. Constant tension through the whole arc.", "Adjust seat so pads touch outer arms. Raise elbows out to sides until parallel to floor. Squeeze side delts. Lower under control.")
    ex("Step-Up", "Legs", "Quads", "Glutes", "Dumbbell", "Secondary", "Med", "High", "Lunge", 48, "Mid", "Functional unilateral strength. High carryover to running and hiking.", "Step one foot onto box. Drive through that heel to stand tall. Lower back down slowly. Do not push off the floor with bottom foot.")
    ex("Running", "Cardio", "Quads", "Cardio", "Bodyweight", "Secondary", "Low", "High", "Locomotion", 24, "Mid", "Primary cardiovascular endurance training.", "Maintain an upright posture with gaze forward. Land mid-foot under your center of mass. Keep a consistent rhythm.")
}